import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as px # Grafik için yeni kütüphaneimport warningswarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(page_title="Bostanlı Çözüm VIP", layout="wide", page_icon="🏫")hide_st_style = """            <style>            #MainMenu {visibility: hidden;}            footer {visibility: hidden;}            header {visibility: hidden;}            #stDecoration {display:none;}            .stDeployButton {display:none;}            button[title="Manage app"], [data-testid="stManageApp"] {display: none !important;}            </style>            """st.markdown(hide_st_style, unsafe_allow_html=True)# --- 2. ŞİFRE SİSTEMİ ---def check_password():    if "password_correct" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Giriş Yap"):            if pwd == "cozum35":                st.session_state["password_correct"] = True                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. YAN MENÜ ---    st.sidebar.title("🏫 Çözüm VIP")    sayfa = st.sidebar.radio("İşlem Seçiniz:", ["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    # --- 📞 VELİ GÖRÜŞMELERİ ---    if sayfa == "📞 Veli Görüşmeleri":        st.header("📞 Veli Görüşme Kayıt")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("v_form", clear_on_submit=True):            c1, c2 = st.columns(2)            v_ad = c1.text_input("Veli / Öğrenci Ad Soyad")            v_tel = c1.text_input("Telefon Numarası")            v_konu = c2.selectbox("Konu", ["Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Rehberlik", "Taksit", "Diğer"])            v_durum = c2.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Görüşme Notları")            if st.form_submit_button("Kaydı Tamamla"):                if v_ad and v_tel:                    new = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success(f"✅ {v_ad} kaydedildi.")                    st.markdown(f'[(🟢 WhatsApp Mesajı Gönder)]({wa_link(v_tel, "Sayın " + v_ad + ", görüşmemiz için teşekkür ederiz.")})')    # --- 💰 KASA İŞLEMLERİ ---    elif sayfa == "💰 Kasa İşlemleri":        st.header("💰 Kasa Giriş / Çıkış")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        k_tip = st.radio("İşlem Türü Seçiniz:", ["Gelir (Tahsilat)", "Gider (Ödeme)"])        if k_tip == "Gelir (Tahsilat)":            k_kalemler = ["Aidat Ödemesi", "Yayın Paketi Ödemesi", "Özel Ders Ödemesi", "Deneme Kulübü Ödemesi", "Kamp Ödemesi", "Diğer Gelir"]        else:            k_kalemler = ["Kira", "Maaş", "Deneme Ücreti", "Kargo", "Elektrik", "Su", "İnternet", "Sabit Telefon", "Cep Telefonu", "Market Alışverişi", "Reklam", "Diğer Gider"]                    k_kat = st.selectbox("Kategori Seçin", k_kalemler)        k_tutar = st.number_input("Tutar (TL)", min_value=0.0, step=10.0)        k_detay = st.text_input("Açıklama (Not)")        if st.button("İşlemi Kasaya Kaydet"):            if k_tutar > 0:                new_k = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success(f"💰 {k_kat} işlemi başarıyla kaydedildi.")            else:                st.warning("Lütfen tutar giriniz.")    # --- 📊 KURUCU RAPORU ---    elif sayfa == "📊 Kurucu Raporu":        st.header("📊 Günlük Finansal Özet")        t_sec = st.date_input("Tarih Seç", datetime.now()).strftime("%Y-%m-%d")        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            dv_b = dv[dv['Tarih'].str.contains(t_sec, na=False)]            dk_b = dk[dk['Tarih'] == t_sec]                        gelir = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']['Miktar'].astype(float).sum()            gider = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']['Miktar'].astype(float).sum()                        c1, c2, c3 = st.columns(3)            c1.metric("Görüşme", len(dv_b))            c2.metric("Gelir", f"{gelir:,.0f} TL")            c3.metric("Gider", f"{gider:,.0f} TL")                        txt = f"*📌 ÇÖZÜM RAPORU ({t_sec})*\n📞 Görüşme: {len(dv_b)}\n💰 Gelir: {gelir:,.0f} TL\n💸 Gider: {gider:,.0f} TL\n📈 Net: {gelir-gider:,.0f} TL"            st.info(txt)            st.markdown(f'[(📲 WhatsApp ile Gönder)]({wa_link("905492551912", txt)})')        except:            st.warning("Veri bulunamadı.")    # --- 📈 GELİŞMİŞ ANALİZ (YENİ SEKME) ---    elif sayfa == "📈 Gelişmiş Analiz":        st.header("📈 Finansal ve Operasyonel Analiz")                try:            dk = conn.read(worksheet="kasa", ttl=0)            dk['Miktar'] = dk['Miktar'].astype(float)            dk['Tarih'] = pd.to_datetime(dk['Tarih'])                        # Filtreleme Seçenekleri            col_f1, col_f2 = st.columns(2)            bas_tar = col_f1.date_input("Başlangıç Tarihi", datetime.now() - timedelta(days=30))            bit_tar = col_f2.date_input("Bitiş Tarihi", datetime.now())                        mask = (dk['Tarih'] >= pd.Timestamp(bas_tar)) & (dk['Tarih'] <= pd.Timestamp(bit_tar))            df_filtre = dk.loc[mask]                        # Üst Özet Metrikler            total_gelir = df_filtre[df_filtre['Tip'] == 'Gelir (Tahsilat)']['Miktar'].sum()            total_gider = df_filtre[df_filtre['Tip'] == 'Gider (Ödeme)']['Miktar'].sum()                        m1, m2, m3 = st.columns(3)            m1.metric("Toplam Gelir", f"{total_gelir:,.0f} TL")            m2.metric("Toplam Gider", f"{total_gider:,.0f} TL")            m3.metric("Net Durum", f"{total_gelir - total_gider:,.0f} TL", delta=total_gelir - total_gider)                        st.divider()                        # Grafik Alanı            c_g1, c_g2 = st.columns(2)                        # Gelir Pastası            df_gelir_pasta = df_filtre[df_filtre['Tip'] == 'Gelir (Tahsilat)'].groupby('Kategori')['Miktar'].sum().reset_index()            fig_gelir = px.pie(df_gelir_pasta, values='Miktar', names='Kategori', title="💰 Gelir Kaynakları", hole=0.4, color_discrete_sequence=px.colors.qualitative.Pastel)            c_g1.plotly_chart(fig_gelir, use_container_width=True)                        # Gider Pastası            df_gider_pasta = df_filtre[df_filtre['Tip'] == 'Gider (Ödeme)'].groupby('Kategori')['Miktar'].sum().reset_index()            fig_gider = px.pie(df_gider_pasta, values='Miktar', names='Kategori', title="💸 Gider Dağılımı", hole=0.4, color_discrete_sequence=px.colors.qualitative.Set3)            c_g2.plotly_chart(fig_gider, use_container_width=True)                    except Exception as e:            st.error(f"Grafikler oluşturulurken bir hata oluştu. Lütfen kasa verilerini kontrol edin. Hata: {e}")